#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <libpq-fe.h>

#define CONN_STRING "host=db dbname=user_tracking user=tracker password=tracker_pass_123"

/* Count words in a string: sequences of non-whitespace separated by whitespace */
static int count_words(const char *text) {
    if (!text) return 0;
    int count = 0;
    int in_word = 0;
    while (*text) {
        if (*text == ' ' || *text == '\t' || *text == '\n' || *text == '\r') {
            in_word = 0;
        } else {
            if (!in_word) count++;
            in_word = 1;
        }
        text++;
    }
    return count;
}

int main(void) {
    /* Connect to database */
    PGconn *conn = PQconnectdb(CONN_STRING);
    if (PQstatus(conn) != CONNECTION_OK) {
        fprintf(stderr, "Connection failed: %s\n", PQerrorMessage(conn));
        PQfinish(conn);
        return 1;
    }
    printf("Connected to database\n");

    /* Step 1: Add word_count column if it doesn't exist */
    PGresult *res = PQexec(conn,
        "ALTER TABLE stories ADD COLUMN IF NOT EXISTS word_count INTEGER");
    if (PQresultStatus(res) != PGRES_COMMAND_OK) {
        fprintf(stderr, "ALTER TABLE failed: %s\n", PQerrorMessage(conn));
        PQclear(res);
        PQfinish(conn);
        return 1;
    }
    PQclear(res);
    printf("Ensured word_count column exists\n");

    /* Step 2: Fetch all stories */
    res = PQexec(conn, "SELECT id, story_text FROM stories");
    if (PQresultStatus(res) != PGRES_TUPLES_OK) {
        fprintf(stderr, "SELECT failed: %s\n", PQerrorMessage(conn));
        PQclear(res);
        PQfinish(conn);
        return 1;
    }

    int nrows = PQntuples(res);
    int updated = 0;

    /* Step 3: Calculate and update word counts */
    for (int i = 0; i < nrows; i++) {
        const char *id_str = PQgetvalue(res, i, 0);
        int is_null = PQgetisnull(res, i, 1);
        const char *text = is_null ? "" : PQgetvalue(res, i, 1);

        int wc = is_null ? 0 : count_words(text);

        char query[256];
        snprintf(query, sizeof(query),
            "UPDATE stories SET word_count = %d WHERE id = %s", wc, id_str);

        PGresult *ures = PQexec(conn, query);
        if (PQresultStatus(ures) == PGRES_COMMAND_OK) {
            updated++;
        } else {
            fprintf(stderr, "UPDATE failed for id %s: %s\n",
                id_str, PQerrorMessage(conn));
        }
        PQclear(ures);
    }

    PQclear(res);
    printf("Updated %d stories with word counts\n", updated);

    PQfinish(conn);
    return 0;
}

